const slug = $('Bookie Pipeline').item.json.book_slug;
const response = $('Scan Books').item.json;
const books = response.books || {};
const fileMap = books[slug] || {};

// Define pipeline phases and their key artifacts
const phases = [
  { id: '02', name: 'Research',        artifact: 'notes.md',               workflowId: 'PLACEHOLDER_02' },
  { id: '03', name: 'Storyboard',      artifact: 'storyboard.md',          workflowId: 'zUNMy5NQMHXbrNBU' },
  { id: '04', name: 'Script',          artifact: 'chunks.md',              workflowId: 'Zdb8sm2EYdwhdzVr' },
  { id: '05', name: 'Voice',           artifact: 'audio/voiceover.wav',    workflowId: 'O2iDURAusKkmQAB8' },
  { id: '06', name: 'Visuals',         artifact: 'image-prompts.md',       workflowId: '9YYIcAKpr3SI7kNf' },
  { id: '07', name: 'Render',          artifact: 'output/video.mp4',       workflowId: 'cxEVlQIrsEOU5oH4' },
  { id: '08', name: 'Post-production', artifact: 'metadata.md',            workflowId: 'PLACEHOLDER_08' }
];

// Build artifact status
const artifacts = {};
for (const p of phases) {
  artifacts[p.artifact] = fileMap[p.artifact] === true;
}

// Determine current stage
let currentPhaseIndex = -1;
for (let i = 0; i < phases.length; i++) {
  if (!artifacts[phases[i].artifact]) {
    currentPhaseIndex = i;
    break;
  }
}

let stage, nextWorkflowUrl;
if (currentPhaseIndex === -1) {
  stage = 'Pipeline Complete \u2713';
  nextWorkflowUrl = null;
} else {
  const p = phases[currentPhaseIndex];
  stage = `Ready for ${p.name} (${p.id})`;
  nextWorkflowUrl = p.workflowId.startsWith('PLACEHOLDER')
    ? null
    : `http://localhost:5678/form/${p.workflowId}`;
}

const completedCount = phases.filter(p => artifacts[p.artifact]).length;

// Build summary lines
const lines = [];
for (const p of phases) {
  const done = artifacts[p.artifact];
  lines.push(`${done ? '\u2713' : '\u2717'} ${p.id} ${p.name} — ${p.artifact}`);
}
const summary = lines.join('\n');

return [{ json: {
  slug,
  stage,
  summary,
  artifacts,
  completedCount,
  totalPhases: phases.length,
  nextWorkflowUrl,
  bookExists: Object.keys(fileMap).length > 0,
  phases
} }];

const d = $('Pipeline Status').item.json;
const pct = Math.round((d.completedCount / d.totalPhases) * 100);

let phaseRows = '';
for (const p of d.phases) {
  const done = d.artifacts[p.artifact];
  const icon = done ? '\u2713' : '\u2717';
  const color = done ? '#22c55e' : '#ef4444';
  const link = p.workflowId.startsWith('PLACEHOLDER')
    ? `<span style="color:#64748b">not yet created</span>`
    : `<a href="http://localhost:5678/form/${p.workflowId}" style="color:#38bdf8;text-decoration:none">Run ${p.id}</a>`;
  phaseRows += `<tr>
    <td style="padding:8px 12px;color:${color};font-size:18px;text-align:center">${icon}</td>
    <td style="padding:8px 12px;font-weight:600">${p.id} ${p.name}</td>
    <td style="padding:8px 12px;color:#94a3b8;font-size:13px">${p.artifact}</td>
    <td style="padding:8px 12px;text-align:center">${link}</td>
  </tr>`;
}

const nextBtn = d.nextWorkflowUrl
  ? `<a href="${d.nextWorkflowUrl}" style="display:inline-block;margin-top:20px;padding:12px 28px;background:#3b82f6;color:#fff;border-radius:8px;text-decoration:none;font-weight:600;font-size:15px">\u25B6 Go to next step</a>`
  : (d.stage.includes('Complete') ? '<p style="color:#22c55e;font-weight:600;margin-top:20px">\u2713 All phases complete!</p>' : '<p style="color:#f59e0b;margin-top:20px">Next workflow not yet created.</p>');

const barColor = pct === 100 ? '#22c55e' : '#3b82f6';

const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><title>Pipeline — ${d.slug}</title></head>
<body style="font-family:system-ui,-apple-system,sans-serif;max-width:700px;margin:40px auto;padding:0 20px;background:#0f172a;color:#e2e8f0">
  <h1 style="font-size:22px;margin-bottom:4px">Pipeline: ${d.slug}</h1>
  <p style="color:#94a3b8;margin-bottom:20px">${d.stage}</p>

  <div style="background:#1e293b;border-radius:8px;height:28px;overflow:hidden;margin-bottom:24px;position:relative">
    <div style="background:${barColor};height:100%;width:${pct}%;transition:width .3s;border-radius:8px"></div>
    <span style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);font-size:13px;font-weight:600">${d.completedCount}/${d.totalPhases} phases (${pct}%)</span>
  </div>

  <table style="border-collapse:collapse;width:100%">
    <thead><tr style="background:#1e293b">
      <th style="padding:8px 12px;width:36px"></th>
      <th style="padding:8px 12px;text-align:left">Phase</th>
      <th style="padding:8px 12px;text-align:left">Artifact</th>
      <th style="padding:8px 12px;text-align:center">Action</th>
    </tr></thead>
    <tbody>${phaseRows}</tbody>
  </table>

  ${nextBtn}

  <p style="color:#64748b;font-size:11px;margin-top:32px">Generated ${new Date().toISOString()}</p>
</body>
</html>`;

return [{ json: { report: html } }];
